# IOUSBDeviceDescriptor

## Declaration

```swift
struct IOUSBDeviceDescriptor {
   UInt8 bLength;
   UInt8 bDescriptorType;
   UInt16 bcdUSB;
   UInt8 bDeviceClass;
   UInt8 bDeviceSubClass;
   UInt8 bDeviceProtocol;
   UInt8 bMaxPacketSize0;
   UInt16 idVendor;
   UInt16 idProduct;
   UInt16 bcdDevice;
   UInt8 iManufacturer;
   UInt8 iProduct;
   UInt8 iSerialNumber;
   UInt8 bNumConfigurations;
};
